class MetadataBuilder:
    """
    Builds gRPC metadata from HTTP headers and user input.
    
    gRPC metadata is a list of key-value tuples where:
    - Keys must be lowercase ASCII strings
    - Binary values use keys ending with '-bin'
    - Standard HTTP headers are prefixed to avoid conflicts
    """

    # Headers that should be forwarded from HTTP to gRPC
    FORWARDED_HEADERS = {
        "authorization",
        "x-request-id",
        "x-correlation-id",
        "x-trace-id",
        "x-span-id",
        "x-forwarded-for",
        "x-forwarded-host",
        "x-forwarded-proto",
        "accept-language",
        "user-agent",
        "x-api-key",
        "x-tenant-id",
        "x-session-id",
        "x-device-id",
        "x-client-version",
    }

    # Headers that should never be forwarded
    BLOCKED_HEADERS = {
        "host",
        "content-length",
        "content-type",
        "connection",
        "keep-alive",
        "transfer-encoding",
        "te",
        "upgrade",
    }

    # Prefix for custom headers
    CUSTOM_HEADER_PREFIX = "x-custom-"
    GRPC_METADATA_PREFIX = "x-gw-"

    @classmethod
    def build_metadata_from_headers(
        cls,
        http_headers: Dict[str, str],
        additional_metadata: Optional[Dict[str, str]] = None,
        forward_all_custom: bool = True,
    ) -> List[Tuple[str, str]]:
        """
        Build gRPC metadata from HTTP headers.
        
        Args:
            http_headers: Dictionary of HTTP headers
            additional_metadata: Extra metadata to include
            forward_all_custom: If True, forward all x-custom-* headers
            
        Returns:
            List of (key, value) tuples suitable for gRPC metadata
        """
        metadata = []

        for key, value in http_headers.items():
            normalized_key = key.lower().strip()
            
            # Skip blocked headers
            if normalized_key in cls.BLOCKED_HEADERS:
                continue

            # Forward known headers
            if normalized_key in cls.FORWARDED_HEADERS:
                grpc_key = cls._sanitize_metadata_key(normalized_key)
                metadata.append((grpc_key, str(value)))
                continue

            # Forward custom headers
            if forward_all_custom and normalized_key.startswith(cls.CUSTOM_HEADER_PREFIX):
                grpc_key = cls._sanitize_metadata_key(normalized_key)
                metadata.append((grpc_key, str(value)))
                continue

        # Add additional metadata
        if additional_metadata:
            for key, value in additional_metadata.items():
                grpc_key = cls._sanitize_metadata_key(key.lower())
                metadata.append((grpc_key, str(value)))

        # Add gateway metadata
        metadata.append(("x-gateway-timestamp", str(int(time.time() * 1000))))
        metadata.append(("x-gateway-version", "1.0.0"))

        return metadata

    @classmethod
    def build_metadata_from_user_input(
        cls, user_input: Dict[str, Any]
    ) -> List[Tuple[str, str]]:
        """
        Build gRPC metadata from structured user input.
        
        Args:
            user_input: Dictionary containing user-specified metadata fields
            
        Returns:
            List of (key, value) tuples
        """
        metadata = []

        # Extract authentication info
        if "auth_token" in user_input:
            metadata.append(("authorization", f"Bearer {user_input['auth_token']}"))

        if "api_key" in user_input:
            metadata.append(("x-api-key", user_input["api_key"]))

        # Extract tracing info
        if "trace_id" in user_input:
            metadata.append(("x-trace-id", user_input["trace_id"]))

        if "correlation_id" in user_input:
            metadata.append(("x-correlation-id", user_input["correlation_id"]))

        # Extract tenant/session info
        if "tenant_id" in user_input:
            metadata.append(("x-tenant-id", user_input["tenant_id"]))

        if "session_id" in user_input:
            metadata.append(("x-session-id", user_input["session_id"]))

        # Extract custom fields
        if "custom_metadata" in user_input and isinstance(
            user_input["custom_metadata"], dict
        ):
            for key, value in user_input["custom_metadata"].items():
                safe_key = cls._sanitize_metadata_key(f"x-custom-{key}")
                metadata.append((safe_key, str(value)))

        return metadata

    @staticmethod
    def _sanitize_metadata_key(key: str) -> str:
        """Sanitize a metadata key for gRPC compliance."""
        # gRPC metadata keys must be lowercase ASCII, no spaces
        sanitized = key.lower().strip()
        sanitized = sanitized.replace(" ", "-")
        # Remove non-ASCII and invalid characters
        sanitized = "".join(
            c for c in sanitized if c.isalnum() or c in "-_."
        )
        return sanitized

    @classmethod
    def extract_metadata_to_headers(
        cls, grpc_metadata: List[Tuple[str, str]]
    ) -> Dict[str, str]:
        """Convert gRPC metadata back to HTTP headers for responses."""
        headers = {}
        for key, value in grpc_metadata:
            if not key.startswith("grpc-"):  # Skip internal gRPC headers
                headers[key] = value
        return headers


