# gRPC Client Interceptor - Attaches metadata to outgoing calls
# ============================================================

class MetadataClientInterceptor(
    grpc.UnaryUnaryClientInterceptor,
    grpc.UnaryStreamClientInterceptor,
):
    """
    Client interceptor that automatically attaches metadata to all outgoing gRPC calls.
    """

    def __init__(self, default_metadata: Optional[List[Tuple[str, str]]] = None):
        self._default_metadata = default_metadata or []

    def _add_metadata(self, client_call_details, additional_metadata=None):
        """Add metadata to the call details."""
        metadata = list(self._default_metadata)
        
        if client_call_details.metadata:
            metadata.extend(client_call_details.metadata)
        
        if additional_metadata:
            metadata.extend(additional_metadata)

        new_details = _ClientCallDetails(
            method=client_call_details.method,
            timeout=client_call_details.timeout,
            metadata=metadata,
            credentials=client_call_details.credentials,
            wait_for_ready=client_call_details.wait_for_ready,
            compression=client_call_details.compression,
        )
        return new_details

    def intercept_unary_unary(self, continuation, client_call_details, request):
        new_details = self._add_metadata(client_call_details)
        return continuation(new_details, request)

    def intercept_unary_stream(self, continuation, client_call_details, request):
        new_details = self._add_metadata(client_call_details)
        return continuation(new_details, request)


class _ClientCallDetails(
    grpc.ClientCallDetails
):
    """Implementation of ClientCallDetails with mutable fields."""

    def __init__(self, method, timeout, metadata, credentials, wait_for_ready, compression):
        self.method = method
        self.timeout = timeout
        self.metadata = metadata
        self.credentials = credentials
        self.wait_for_ready = wait_for_ready
        self.compression = compression


