class BackendServiceClient:
    """
    gRPC client for communicating with backend services.
    Handles metadata propagation and request forwarding.
    """

    def __init__(
        self,
        target: str,
        default_metadata: Optional[List[Tuple[str, str]]] = None,
        timeout: float = 30.0,
        use_tls: bool = False,
        root_certificates: Optional[bytes] = None,
    ):
        self._target = target
        self._timeout = timeout
        self._default_metadata = default_metadata or []

        # Create interceptor
        interceptor = MetadataClientInterceptor(default_metadata=self._default_metadata)

        # Create channel
        if use_tls:
            credentials = grpc.ssl_channel_credentials(
                root_certificates=root_certificates
            )
            channel = grpc.secure_channel(target, credentials)
        else:
            channel = grpc.insecure_channel(target)

        # Apply interceptor
        self._channel = grpc.intercept_channel(channel, interceptor)

        # Method descriptors for generic calls
        self._process_request_method = "/gateway.BackendService/ProcessRequest"
        self._health_check_method = "/gateway.BackendService/HealthCheck"
        self._stream_data_method = "/gateway.BackendService/StreamData"

    def process_request(
        self,
        request: GatewayRequest,
        metadata: Optional[List[Tuple[str, str]]] = None,
        timeout: Optional[float] = None,
    ) -> Tuple[GatewayResponse, List[Tuple[str, str]], List[Tuple[str, str]]]:
        """
        Forward a request to the backend service.
        
        Args:
            request: The gateway request to forward
            metadata: Additional metadata to attach to the call
            timeout: Optional timeout override
            
        Returns:
            Tuple of (response, initial_metadata, trailing_metadata)
        """
        call_timeout = timeout or self._timeout
        
        # Create the unary-unary multi-callable
        multi_callable = self._channel.unary_unary(
            self._process_request_method,
            request_serializer=GatewayRequest.SerializeToString,
            response_deserializer=GatewayResponse.FromString,
        )

        # Make the call with metadata
        call = multi_callable.future(
            request,
            metadata=metadata,
            timeout=call_timeout,
        )

        try:
            response = call.result(timeout=call_timeout)
            initial_metadata = list(call.initial_metadata() or [])
            trailing_metadata = list(call.trailing_metadata() or [])
            return response, initial_metadata, trailing_metadata
        except grpc.RpcError as e:
            raise BackendServiceError(
                f"Backend call failed: {e.code()} - {e.details()}",
                status_code=e.code(),
                details=e.details(),
            )

    def stream_data(
        self,
        request: GatewayRequest,
        metadata: Optional[List[Tuple[str, str]]] = None,
        timeout: Optional[float] = None,
    ):
        """Forward a streaming request to the backend service."""
        call_timeout = timeout or self._timeout
        
        multi_callable = self._channel.unary_stream(
            self._stream_data_method,
            request_serializer=GatewayRequest.SerializeToString,
            response_deserializer=GatewayResponse.FromString,
        )

        call = multi_callable(
            request,
            metadata=metadata,
            timeout=call_timeout,
        )

        return call

    def health_check(
        self,
        service_name: str,
        metadata: Optional[List[Tuple[str, str]]] = None,
    ) -> HealthCheckResponse:
        """Check health of backend service."""
        multi_callable = self._channel.unary_unary(
            self._health_check_method,
            request_serializer=HealthCheckRequest.SerializeToString,
            response_deserializer=HealthCheckResponse.FromString,
        )

        request = HealthCheckRequest(service_name=service_name)
        
        try:
            response = multi_callable(
                request,
                metadata=metadata,
                timeout=5.0,
            )
            return response
        except grpc.RpcError as e:
            return HealthCheckResponse(
                healthy=False,
                message=f"Health check failed: {e.details()}"
            )

    def close(self):
        """Close the gRPC channel."""
        if self._channel:
            self._channel.close()


class BackendServiceError(Exception):
    """Exception for backend service errors."""
    def __init__(self, message, status_code=None, details=None):
        super().__init__(message)
        self.status_code = status_code
        self.details = details


