# Gateway Service - The actual gRPC service that handles incoming requests
# ============================================================

class GatewayServiceServicer:
    """
    Gateway service that receives requests and forwards them to backend services.
    Uses context.set_trailing_metadata() to pass metadata back to clients.
    """

    def __init__(self, backend_configs: Dict[str, str]):
        """
        Args:
            backend_configs: Mapping of service_name -> backend_address
        """
        self._backend_clients: Dict[str, BackendServiceClient] = {}
        self._route_map: Dict[str, str] = {}

        # Initialize backend clients
        for service_name, address in backend_configs.items():
            self._backend_clients[service_name] = BackendServiceClient(
                target=address,
                default_metadata=[
                    ("x-gateway-source", "api-gateway"),
                    ("x-backend-service", service_name),
                ],
            )

        # Setup route mapping
        self._setup_routes()

    def _setup_routes(self):
        """Configure path-to-service routing."""
        self._route_map = {
            "/api/users": "user-service",
            "/api/orders": "order-service",
            "/api/products": "product-service",
            "/api/payments": "payment-service",
            "/api/notifications": "notification-service",
        }

    def _resolve_backend(self, path: str) -> Optional[str]:
        """Resolve the backend service for a given path."""
        for route_prefix, service_name in self._route_map.items():
            if path.startswith(route_prefix):
                return service_name
        return None

    def ForwardRequest(self, request_data: Dict[str, Any], context) -> Dict[str, Any]:
        """
        Main handler for forwarding requests to backend services.
        
        This method:
        1. Extracts HTTP headers from the incoming request
        2. Builds gRPC metadata from those headers
        3. Resolves the appropriate backend service
        4. Forwards the request with metadata
        5. Sets trailing metadata on the response context
        """
        # Extract request info
        method = request_data.get("method", "GET")
        path = request_data.get("path", "/")
        body = request_data.get("body", "")
        http_headers = request_data.get("headers", {})
        user_input = request_data.get("user_input", {})

        # Generate request ID if not present
        import uuid
        request_id = http_headers.get("x-request-id", str(uuid.uuid4()))

        print(f"[Gateway] Received request: {method} {path} (ID: {request_id})")

        # Step 1: Build metadata from HTTP headers
        header_metadata = MetadataBuilder.build_metadata_from_headers(
            http_headers=http_headers,
            additional_metadata={"x-request-id": request_id},
        )

        # Step 2: Build metadata from user input
        user_metadata = MetadataBuilder.build_metadata_from_user_input(user_input)

        # Step 3: Combine all metadata
        combined_metadata = header_metadata + user_metadata
        
        print(f"[Gateway] Built metadata with {len(combined_metadata)} entries:")
        for key, value in combined_metadata:
            # Mask sensitive values in logs
            display_value = "***" if key in ("authorization", "x-api-key") else value
            print(f"  {key}: {display_value}")

        # Step 4: Resolve backend service
        service_name = self._resolve_backend(path)
        if not service_name:
            # Set error trailing metadata
            error_metadata = [
                ("x-error-code", "ROUTE_NOT_FOUND"),
                ("x-error-message", f"No backend service for path: {path}"),
                ("x-request-id", request_id),
            ]
            context.set_trailing_metadata(error_metadata)
            return {
                "status_code": 404,
                "body": json.dumps({"error": f"No route found for {path}"}),
                "response_headers": {},
                "trailing_metadata": error_metadata,
            }

        backend_client = self._backend_clients.get(service_name)
        if not backend_client:
            error_metadata = [
                ("x-error-code", "SERVICE_UNAVAILABLE"),
                ("x-error-message", f"Backend service not configured: {service_name}"),
                ("x-request-id", request_id),
            ]
            context.set_trailing_metadata(error_metadata)
            return {
                "status_code": 503,
                "body": json.dumps({"error": f"Service unavailable: {service_name}"}),
                "response_headers": {},
                "trailing_metadata": error_metadata,
            }

        # Step 5: Create backend request
        backend_request = GatewayRequest(
            method=method,
            path=path,
            body=body,
            headers=http_headers,
            request_id=request_id,
        )

        # Step 6: Forward to backend with metadata
        try:
            response, initial_metadata, trailing_metadata = backend_client.process_request(
                request=backend_request,
                metadata=combined_metadata,
            )

            # Step 7: Build response trailing metadata
            response_trailing_metadata = [
                ("x-request-id", request_id),
                ("x-backend-service", service_name),
                ("x-gateway-processed", "true"),
                ("x-response-timestamp", str(int(time.time() * 1000))),
            ]

            # Include backend trailing metadata
            if trailing_metadata:
                response_trailing_metadata.extend(trailing_metadata)

            # Set trailing metadata on the context
            context.set_trailing_metadata(response_trailing_metadata)

            print(f"[Gateway] Response from {service_name}: status={response.status_code}")
            print(f"[Gateway] Trailing metadata entries: {len(response_trailing_metadata)}")

            # Convert response headers
            response_headers = MetadataBuilder.extract_metadata_to_headers(
                initial_metadata
            )

            return {
                "status_code": response.status_code,
                "body": response.body,
                "response_headers": response_headers,
                "trailing_metadata": response_trailing_metadata,
            }

        except BackendServiceError as e:
            error_metadata = [
                ("x-error-code", str(e.status_code)),
                ("x-error-message", str(e.details)),
                ("x-request-id", request_id),
                ("x-backend-service", service_name),
            ]
            context.set_trailing_metadata(error_metadata)
            
            return {
                "status_code": 502,
                "body": json.dumps({"error": "Backend service error", "details": str(e)}),
                "response_headers": {},
                "trailing_metadata": error_metadata,
            }

        except Exception as e:
            error_metadata = [
                ("x-error-code", "INTERNAL_ERROR"),
                ("x-error-message", str(e)),
                ("x-request-id", request_id),
            ]
            context.set_trailing_metadata(error_metadata)

            return {
                "status_code": 500,
                "body": json.dumps({"error": "Internal gateway error"}),
                "response_headers": {},
                "trailing_metadata": error_metadata,
            }

    def close(self):
        """Clean up all backend connections."""
        for client in self._backend_clients.values():
            client.close()


