# Service Registry and Load Balancing
# ============================================================

class ServiceRegistry:
    """Simple service registry for backend service discovery."""

    def __init__(self):
        self._services: Dict[str, List[str]] = {}
        self._round_robin_index: Dict[str, int] = {}

    def register(self, service_name: str, address: str):
        if service_name not in self._services:
            self._services[service_name] = []
            self._round_robin_index[service_name] = 0
        if address not in self._services[service_name]:
            self._services[service_name].append(address)

    def deregister(self, service_name: str, address: str):
        if service_name in self._services:
            self._services[service_name] = [
                a for a in self._services[service_name] if a != address
            ]

    def get_address(self, service_name: str) -> Optional[str]:
        """Get next address using round-robin."""
        addresses = self._services.get(service_name, [])
        if not addresses:
            return None
        
        index = self._round_robin_index.get(service_name, 0)
        address = addresses[index % len(addresses)]
        self._round_robin_index[service_name] = index + 1
        return address

    def get_all_addresses(self, service_name: str) -> List[str]:
        return self._services.get(service_name, [])


# ============================================================
# Full Gateway Server Setup
# ============================================================

def create_gateway_server(
    gateway_port: int = 50051,
    backend_configs: Optional[Dict[str, str]] = None,
) -> grpc.Server:
    """
    Create and configure the gateway gRPC server.
    
    Args:
        gateway_port: Port for the gateway to listen on
        backend_configs: Backend service configurations
        
    Returns:
        Configured gRPC server (not yet started)
    """
    if backend_configs is None:
        backend_configs = {
            "user-service": "localhost:50052",
            "order-service": "localhost:50053",
            "product-service": "localhost:50054",
            "payment-service": "localhost:50055",
            "notification-service": "localhost:50056",
        }

    server = grpc.server(
        futures.ThreadPoolExecutor(max_workers=10),
        options=[
            ("grpc.max_send_message_length", 50 * 1024 * 1024),  # 50MB
            ("grpc.max_receive_message_length", 50 * 1024 * 1024),  # 50MB
            ("grpc.keepalive_time_ms", 10000),
            ("grpc.keepalive_timeout_ms", 5000),
        ],
    )

    # Note: In production, you would add the generated servicer here
    # gateway_pb2_grpc.add_GatewayServiceServicer_to_server(servicer, server)

    server.add_insecure_port(f"[::]:{gateway_port}")
    return server


